```class Solution {
public:
    int numberOfArrays(string s, int k) {
        int n = s.size(), mod = 1e9 + 7;
        vector<int> dp(n + 1, 0);
        dp[0] = 1;
        for (int i = 0; i < n; i++) {
            for (int j = i; j >= 0; j--) {
                int num = stoi(s.substr(j, i - j + 1));
                if (num <= k) dp[i + 1] = (dp[i + 1] + dp[j]) % mod;
            }
        }
        return dp[n];
    }
};
